const cp = require('child_process');
const body = $json.body || $json;
const action = body.action || 'ps';
const container = body.container || '';
const NIN_CONTAINERS = new Set(['n8n-lucy', 'qdrant-lucy', 'searxng-lucy']);

try {
  if (action === 'ps' || action === 'status') {
    const out = cp.execSync('docker ps -a --format "{{.Names}}\t{{.Status}}"').toString();
    return [{ json: { output: '🐳 Contenedores:\n' + out } }];
  }
  if (['restart', 'stop', 'start', 'logs'].includes(action)) {
    if (!container) return [{ json: { output: '❌ Falta el parámetro container' } }];
    if (!NIN_CONTAINERS.has(container)) return [{ json: { output: '⛔ Solo puedo operar contenedores NIN: ' + [...NIN_CONTAINERS].join(', ') } }];
    if (action === 'logs') {
      const out = cp.execSync(`docker logs --tail 50 ${container}`).toString();
      return [{ json: { output: '📋 Logs de ' + container + ':\n' + out } }];
    }
    cp.execSync(`docker ${action} ${container}`);
    return [{ json: { output: '✅ ' + action + ' exitoso: ' + container } }];
  }
  return [{ json: { output: '❌ Acción desconocida: ' + action + '. Usa: ps, restart, stop, start, logs' } }];
} catch(e) {
  return [{ json: { output: '❌ Error: ' + e.message } }];
}
